from typing import Literal
from pydantic import BaseModel, computed_field, field_validator

AxisKey = Literal[
    "spec_disambiguation",
    "ai_leverage",
    "system_sense",
    "code_doc_quality",
    "empathy",
]
Recommendation = Literal["Strong Yes", "Discussion", "No"]

AXIS_CONFIG: dict[str, dict] = {
    "spec_disambiguation": {"label": "Spec Disambiguation", "max_score": 5},
    "ai_leverage":         {"label": "AI Leverage 통제",    "max_score": 5},
    "system_sense":        {"label": "System Sense",        "max_score": 6},
    "code_doc_quality":    {"label": "Code/Doc Quality",    "max_score": 6},
    "empathy":             {"label": "Empathy",             "max_score": 3},
}


class AxisScore(BaseModel):
    axis: AxisKey
    score: int
    signals_found: list[str]
    signals_missing: list[str]
    justification: str

    @field_validator("score")
    @classmethod
    def clamp_score(cls, v: int, info) -> int:
        axis = info.data.get("axis")
        if axis and axis in AXIS_CONFIG:
            return max(0, min(v, AXIS_CONFIG[axis]["max_score"]))
        return max(0, v)

    @computed_field
    @property
    def label(self) -> str:
        return AXIS_CONFIG[self.axis]["label"]

    @computed_field
    @property
    def max_score(self) -> int:
        return AXIS_CONFIG[self.axis]["max_score"]


class EvaluationResult(BaseModel):
    axes: list[AxisScore]
    anti_patterns_found: list[str]
    security_signals: list[str]
    discussion_questions: list[str]
    summary: str

    @computed_field
    @property
    def total_score(self) -> int:
        return sum(a.score for a in self.axes)

    @computed_field
    @property
    def max_score(self) -> int:
        return 25

    @computed_field
    @property
    def recommendation(self) -> Recommendation:
        if self.anti_patterns_found:
            if self.total_score < 20:
                return "No"
        if self.total_score >= 20:
            return "Strong Yes"
        if self.total_score >= 15:
            return "Discussion"
        return "No"

