import subprocess
import tempfile
from pathlib import Path

INCLUDE_EXTENSIONS = {
    ".py", ".js", ".ts", ".jsx", ".tsx",
    ".md", ".toml", ".yaml", ".yml",
    ".json", ".txt", ".sh", ".env.example",
}
EXCLUDE_DIRS = {
    "__pycache__", ".git", "node_modules",
    ".venv", "venv", "env", "dist", "build",
    ".pytest_cache", ".mypy_cache", ".ruff_cache",
}
MAX_FILE_BYTES = 80_000
MAX_TOTAL_CHARS = 150_000


def read_local(path: str) -> tuple[dict[str, str], str]:
    """Return (files dict, git_log). Prioritizes README then source then tests."""
    base = Path(path).resolve()
    raw: dict[str, str] = {}

    for fp in sorted(base.rglob("*")):
        if not fp.is_file():
            continue
        if any(part in EXCLUDE_DIRS for part in fp.parts):
            continue
        suffix = fp.suffix.lower()
        name = fp.name.lower()
        if suffix not in INCLUDE_EXTENSIONS and name not in {".env.example"}:
            continue
        if fp.stat().st_size > MAX_FILE_BYTES:
            continue
        rel = str(fp.relative_to(base))
        try:
            raw[rel] = fp.read_text(errors="replace")
        except Exception:
            pass

    git_log = _git_log(path)
    files = _prioritize(raw)
    return files, git_log


def _prioritize(raw: dict[str, str]) -> dict[str, str]:
    """Keep README first, then src files, then tests, truncated at MAX_TOTAL_CHARS."""
    order: list[tuple[int, str]] = []
    for path in raw:
        lower = path.lower()
        if "readme" in lower:
            order.append((0, path))
        elif lower.endswith(".md") or lower.endswith(".toml"):
            order.append((1, path))
        elif "test" in lower:
            order.append((3, path))
        else:
            order.append((2, path))

    result: dict[str, str] = {}
    total = 0
    for _, path in sorted(order):
        content = raw[path]
        if total + len(content) > MAX_TOTAL_CHARS:
            remaining = MAX_TOTAL_CHARS - total
            if remaining > 500:
                result[path] = content[:remaining] + "\n... [truncated]"
            break
        result[path] = content
        total += len(content)
    return result


def _git_log(path: str) -> str:
    try:
        result = subprocess.run(
            ["git", "log", "--oneline", "--no-decorate", "-30"],
            cwd=path, capture_output=True, text=True, timeout=10,
        )
        return result.stdout.strip()
    except Exception:
        return ""


def clone_github(url: str) -> tuple[str, tempfile.TemporaryDirectory]:
    tmpdir = tempfile.TemporaryDirectory()
    subprocess.run(
        ["git", "clone", "--depth=50", url, tmpdir.name],
        check=True, timeout=120, capture_output=True,
    )
    return tmpdir.name, tmpdir

