import os
import tempfile
from pathlib import Path
from src.fetcher import read_local, _prioritize, MAX_TOTAL_CHARS


def _make_tree(files: dict[str, str]) -> str:
    tmpdir = tempfile.mkdtemp()
    for rel, content in files.items():
        fp = Path(tmpdir) / rel
        fp.parent.mkdir(parents=True, exist_ok=True)
        fp.write_text(content)
    return tmpdir


def test_reads_python_and_md():
    path = _make_tree({"README.md": "# Hello", "src/main.py": "print('hi')"})
    files, _ = read_local(path)
    assert "README.md" in files
    assert "src/main.py" in files


def test_excludes_pycache():
    path = _make_tree({
        "src/__pycache__/foo.pyc": "garbage",
        "src/main.py": "x = 1",
    })
    files, _ = read_local(path)
    assert not any("__pycache__" in k for k in files)
    assert "src/main.py" in files


def test_excludes_dotgit():
    path = _make_tree({
        ".git/config": "[core]",
        "main.py": "x = 1",
    })
    files, _ = read_local(path)
    assert not any(".git" in k for k in files)


def test_readme_comes_first():
    path = _make_tree({
        "zz_service.py": "x = 1",
        "README.md": "# Title",
        "aa_model.py": "y = 2",
    })
    files, _ = read_local(path)
    keys = list(files.keys())
    assert keys[0] == "README.md"


def test_total_chars_under_limit():
    big_content = "x" * 20_000
    many = {f"file_{i}.py": big_content for i in range(20)}
    result = _prioritize(many)
    assert sum(len(v) for v in result.values()) <= MAX_TOTAL_CHARS


def test_empty_dir_returns_empty():
    path = _make_tree({})
    files, _ = read_local(path)
    assert files == {}

